import React, { useState, useEffect } from 'react';
import { getBooks, createBook, updateBook, deleteBook, getUsers, createUser, deleteUser } from '../api/api';

function AdminBooks({ onUserAdded }) {
  // Books state
  const [books, setBooks] = useState([]);
  const [bookForm, setBookForm] = useState({ id: null, title: '', author: '', isbn: '', totalCopies: 1 });
  const [isEditingBook, setIsEditingBook] = useState(false);

  // Users state
  const [users, setUsers] = useState([]);
  const [userForm, setUserForm] = useState({ name: '', email: '', phone: '' });

  // Messages
  const [message, setMessage] = useState({ text: '', isError: false });
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    fetchBooks();
    fetchUsers();
  }, []);

  const showMessage = (text, isError = false) => {
    setMessage({ text, isError });
    setTimeout(() => setMessage({ text: '', isError: false }), 5000);
  };

  const fetchBooks = async () => {
    try {
      const res = await getBooks();
      setBooks(res.data);
    } catch (error) {
      console.error("Error fetching books:", error);
    }
  };

  const fetchUsers = async () => {
    try {
      const res = await getUsers();
      setUsers(res.data);
    } catch (error) {
      console.error("Error fetching users:", error);
    }
  };

  // Book actions
  const handleBookInputChange = (e) => {
    const { name, value } = e.target;
    setBookForm(prev => ({
      ...prev,
      [name]: name === 'totalCopies' ? parseInt(value, 10) || 0 : value
    }));
  };

  const handleBookSubmit = async (e) => {
    e.preventDefault();
    if (!bookForm.title || !bookForm.author || !bookForm.isbn || bookForm.totalCopies < 0) {
      showMessage("Please fill all book fields correctly.", true);
      return;
    }

    try {
      if (isEditingBook) {
        await updateBook(bookForm.id, {
          title: bookForm.title,
          author: bookForm.author,
          isbn: bookForm.isbn,
          totalCopies: bookForm.totalCopies,
          availableCopies: bookForm.totalCopies // Backend handles delta, but sending it is fine
        });
        showMessage(`Book '${bookForm.title}' updated successfully!`, false);
      } else {
        await createBook({
          title: bookForm.title,
          author: bookForm.author,
          isbn: bookForm.isbn,
          totalCopies: bookForm.totalCopies,
          availableCopies: bookForm.totalCopies
        });
        showMessage(`Book '${bookForm.title}' created successfully!`, false);
      }
      resetBookForm();
      fetchBooks();
    } catch (error) {
      const errMsg = error.response?.data?.error || "Failed to save book.";
      showMessage(errMsg, true);
    }
  };

  const handleEditBookClick = (book) => {
    setBookForm({
      id: book.id,
      title: book.title,
      author: book.author,
      isbn: book.isbn,
      totalCopies: book.totalCopies
    });
    setIsEditingBook(true);
  };

  const handleDeleteBookClick = async (id, title) => {
    if (!window.confirm(`Are you sure you want to delete '${title}'?`)) return;
    try {
      await deleteBook(id);
      showMessage("Book deleted successfully.", false);
      fetchBooks();
    } catch (error) {
      const errMsg = error.response?.data?.error || "Failed to delete book. It might be currently borrowed.";
      showMessage(errMsg, true);
    }
  };

  const resetBookForm = () => {
    setBookForm({ id: null, title: '', author: '', isbn: '', totalCopies: 1 });
    setIsEditingBook(false);
  };

  // User actions
  const handleUserInputChange = (e) => {
    const { name, value } = e.target;
    setUserForm(prev => ({ ...prev, [name]: value }));
  };

  const handleUserSubmit = async (e) => {
    e.preventDefault();
    if (!userForm.name || !userForm.email) {
      showMessage("Name and Email are required.", true);
      return;
    }

    try {
      await createUser(userForm);
      showMessage(`User '${userForm.name}' registered successfully!`, false);
      setUserForm({ name: '', email: '', phone: '' });
      fetchUsers();
      if (onUserAdded) onUserAdded(); // Notify parent to refresh current user info
    } catch (error) {
      const errMsg = error.response?.data?.error || "Failed to register user.";
      showMessage(errMsg, true);
    }
  };

  const handleDeleteUserClick = async (id, name) => {
    if (!window.confirm(`Are you sure you want to delete user '${name}'?`)) return;
    try {
      await deleteUser(id);
      showMessage("User deleted successfully.", false);
      fetchUsers();
      if (onUserAdded) onUserAdded();
    } catch (error) {
      const errMsg = error.response?.data?.error || "Failed to delete user. They may have active borrows.";
      showMessage(errMsg, true);
    }
  };

  return (
    <div className="page">
      <div className="page-header">
        <h2>Admin Management Panel</h2>
      </div>

      {message.text && (
        <div className={`alert-box ${message.isError ? 'alert-error' : 'alert-success'}`}>
          {message.text}
        </div>
      )}

      {/* Books Management Section */}
      <div className="admin-section">
        <h3>Manage Books Catalog</h3>
        <div className="admin-grid">
          {/* Book Form */}
          <div>
            <h4>{isEditingBook ? 'Edit Book' : 'Add New Book'}</h4>
            <form onSubmit={handleBookSubmit} style={{ background: '#f8f9fa', padding: '20px', borderRadius: '4px' }}>
              <div className="form-group">
                <label>Book Title</label>
                <input
                  type="text"
                  name="title"
                  value={bookForm.title}
                  onChange={handleBookInputChange}
                  placeholder="e.g. Code Complete"
                  required
                />
              </div>
              <div className="form-group">
                <label>Author</label>
                <input
                  type="text"
                  name="author"
                  value={bookForm.author}
                  onChange={handleBookInputChange}
                  placeholder="e.g. Steve McConnell"
                  required
                />
              </div>
              <div className="form-group">
                <label>ISBN Number</label>
                <input
                  type="text"
                  name="isbn"
                  value={bookForm.isbn}
                  onChange={handleBookInputChange}
                  placeholder="e.g. 978-0735619678"
                  required
                />
              </div>
              <div className="form-group">
                <label>Total Copies</label>
                <input
                  type="number"
                  name="totalCopies"
                  value={bookForm.totalCopies}
                  onChange={handleBookInputChange}
                  min="0"
                  required
                />
              </div>
              <div style={{ display: 'flex', gap: '10px' }}>
                <button type="submit" className="btn btn-primary">
                  {isEditingBook ? 'Update Book' : 'Add Book'}
                </button>
                {isEditingBook && (
                  <button type="button" className="btn btn-secondary" onClick={resetBookForm}>
                    Cancel
                  </button>
                )}
              </div>
            </form>
          </div>

          {/* Book List Table */}
          <div>
            <h4>Current Books Inventory</h4>
            <table style={{ fontSize: '13px' }}>
              <thead>
                <tr>
                  <th>Title</th>
                  <th>Author</th>
                  <th>ISBN</th>
                  <th>Copies</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {books.map(book => (
                  <tr key={book.id}>
                    <td><strong>{book.title}</strong></td>
                    <td>{book.author}</td>
                    <td><code>{book.isbn}</code></td>
                    <td>{book.availableCopies} / {book.totalCopies}</td>
                    <td>
                      <button
                        className="btn btn-warning btn-sm"
                        onClick={() => handleEditBookClick(book)}
                        style={{ marginRight: '5px' }}
                      >
                        Edit
                      </button>
                      <button
                        className="btn btn-danger btn-sm"
                        onClick={() => handleDeleteBookClick(book.id, book.title)}
                      >
                        Delete
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>

      {/* Users Management Section */}
      <div className="admin-section">
        <h3>Manage User Registrations</h3>
        <div className="admin-grid">
          {/* User Form */}
          <div>
            <h4>Register New User</h4>
            <form onSubmit={handleUserSubmit} style={{ background: '#f8f9fa', padding: '20px', borderRadius: '4px' }}>
              <div className="form-group">
                <label>Full Name</label>
                <input
                  type="text"
                  name="name"
                  value={userForm.name}
                  onChange={handleUserInputChange}
                  placeholder="e.g. Jane Doe"
                  required
                />
              </div>
              <div className="form-group">
                <label>Email Address</label>
                <input
                  type="email"
                  name="email"
                  value={userForm.email}
                  onChange={handleUserInputChange}
                  placeholder="e.g. jane@example.com"
                  required
                />
              </div>
              <div className="form-group">
                <label>Phone Number</label>
                <input
                  type="text"
                  name="phone"
                  value={userForm.phone}
                  onChange={handleUserInputChange}
                  placeholder="e.g. 1234567890"
                />
              </div>
              <button type="submit" className="btn btn-success">Register User</button>
            </form>
          </div>

          {/* User List Table */}
          <div>
            <h4>Registered Library Members</h4>
            <table style={{ fontSize: '13px' }}>
              <thead>
                <tr>
                  <th>ID</th>
                  <th>Name</th>
                  <th>Email</th>
                  <th>Phone</th>
                  <th>Action</th>
                </tr>
              </thead>
              <tbody>
                {users.map(user => (
                  <tr key={user.id}>
                    <td><code>{user.id}</code></td>
                    <td><strong>{user.name}</strong></td>
                    <td>{user.email}</td>
                    <td>{user.phone || '-'}</td>
                    <td>
                      <button
                        className="btn btn-danger btn-sm"
                        onClick={() => handleDeleteUserClick(user.id, user.name)}
                      >
                        Delete
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
}

export default AdminBooks;
